  let sphPos = kinematics[instance_index].pos_mass.xyz;

  // World transform: SPH coords -> scene coords
  let worldInvScale = params.worldOffset_is.w;
  let worldOffset = params.worldOffset_is.xyz;
  let positionScale = params.cameraUp_ps.w;
  let worldPos = (sphPos * worldInvScale + worldOffset) * positionScale;

  // Camera-facing billboard vectors
  let right = params.cameraRight_sz.xyz;
  let up = params.cameraUp_ps.xyz;
  let particleSize = params.cameraRight_sz.w;

  // Size attenuation
  var size = particleSize;
  let useSizeAtten = params.extras.z;
  if (useSizeAtten < 0.5) {
    // Fixed pixel size: scale billboard so it always appears as \`particleSize\` pixels on screen.
    // projScale = projectionMatrix[1][1] = 1/tan(fov/2)
    let viewportHeight = params.extras.x;
    let projScale = params.extras.w;
    let cameraPos = params.cameraPos_cnt.xyz;
    let dist = distance(worldPos, cameraPos);
    let clampedDist = max(dist, 1e-6);
    size = particleSize * clampedDist / (projScale * viewportHeight);
  }
  // For sizeAtten mode (useSizeAtten >= 0.5): size stays as world-unit particleSize.
  // The viewProjection matrix naturally attenuates billboard size with distance.

