  let clipPos = params.viewProjection * vec4<f32>(worldPos + offset, 1.0);

  out.position = clipPos;
  out.uv = corner;

  // Read particle color
  var particleColor = colors[instance_index];

  // Proximity glow near black hole
  let bhGlowRadius = params.bhPos_gr.w;
  if (bhGlowRadius > 0.0) {
    let bhPos = params.bhPos_gr.xyz;
    let dist = distance(worldPos, bhPos);
    if (dist < bhGlowRadius) {
      let t = 1.0 - dist / bhGlowRadius;
      let intensity = t * t;
      let glowTarget = vec3<f32>(0.7, 0.85, 1.0);
      particleColor = vec4<f32>(
        mix(particleColor.rgb, glowTarget, intensity),
        particleColor.a
      );
    }
  }

  let opacity = params.extras.y;
  out.color = vec4<f32>(particleColor.rgb, particleColor.a * opacity);

